    .dgaspc-table {
        width: 100%;
        border-collapse: collapse !important;
        font-family: inherit;
        font-size: 14px;
        min-width: 900px;
        background-color: transparent !important;
        border: none !important;
    }
    /* Override Theme Borders and Backgrounds */
    .dgaspc-table th, 
    .dgaspc-table td {
        border-left: none !important;
        border-right: none !important;
        border-top: none !important;
    }
    /* Striped row fix (prevents theme from making alternating rows gray) */
    .dgaspc-table tr,
    .dgaspc-table tbody tr:nth-child(odd), 
    .dgaspc-table tbody tr:nth-child(even) {
        background-color: transparent !important;
    }
    .dgaspc-table th {
        background-color: #041E3A !important;
        color: #ffffff !important;
        padding: 16px !important;
        text-align: left !important;
        font-size: 12px;
        font-weight: 700;
        letter-spacing: 0.5px;
        text-transform: uppercase;
