    }
    .dgaspc-table td {
        padding: 16px !important;
        border-bottom: 1px solid #e2e8f0 !important;
        color: #334155;
        vertical-align: middle;
        line-height: 1.5;
        background-color: #ffffff !important; /* Force white cells */
    }
    .dgaspc-table tr:last-child td {
        border-bottom: none !important;
    }
    .table-title {
        font-weight: 700;
